using System.ComponentModel;
using System.Net.Http.Json;
using System.Text;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------
string model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";
string? apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY");
string? endpoint = Environment.GetEnvironmentVariable("OPENAI_ENDPOINT");

if (string.IsNullOrWhiteSpace(apiKey))
{
    Console.Error.WriteLine("Set the OPENAI_API_KEY environment variable.");
    return 1;
}

// ---------------------------------------------------------------------------
// Shared state for the note-taking tool
// ---------------------------------------------------------------------------
var notebook = new Notebook();

// ---------------------------------------------------------------------------
// Tool definitions
// ---------------------------------------------------------------------------
var tools = new List<AITool>
{
    AIFunctionFactory.Create(
        ([Description("The search query to look up on the web")] string query) =>
        {
            return WebSearchAsync(query);
        },
        new AIFunctionFactoryOptions
        {
            Name = "web_search",
            Description = "Search the web for information on a topic. Returns a list of results with titles, URLs, and snippets.",
        }),

    AIFunctionFactory.Create(
        (
            [Description("A short title for this note")] string title,
            [Description("The content / finding to save")] string content
        ) =>
        {
            notebook.Add(title, content);
            return $"Note saved: \"{title}\" (total notes: {notebook.Count})";
        },
        new AIFunctionFactoryOptions
        {
            Name = "save_note",
            Description = "Save a research finding or key point to the notebook for later summarisation.",
        }),

    AIFunctionFactory.Create(
        () =>
        {
            return notebook.Count == 0
                ? "The notebook is empty."
                : notebook.ToString();
        },
        new AIFunctionFactoryOptions
        {
            Name = "read_notes",
            Description = "Read all notes saved so far.",
        }),
};

// ---------------------------------------------------------------------------
// Build the chat-client pipeline   (OpenAI → function-invocation)
// ---------------------------------------------------------------------------
OpenAI.OpenAIClient openAIClient = endpoint is not null
    ? new(new ApiKeyCredential(apiKey), new OpenAI.OpenAIClientOptions { Endpoint = new Uri(endpoint) })
    : new(new ApiKeyCredential(apiKey));

IChatClient chatClient = openAIClient
    .GetChatClient(model)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

// ---------------------------------------------------------------------------
// Build the research agent
// ---------------------------------------------------------------------------
var agent = new ChatClientAgent(
    chatClient,
    new ChatClientAgentOptions
    {
        Name = "ResearchAgent",
        Description = "An AI research agent that searches the web and takes notes to produce a summary.",
        ChatOptions = new ChatOptions
        {
            Tools = tools,
            Temperature = 0.2f,
            Instructions = """
                You are a thorough research agent. When given a topic:
                1. Break the topic into 2-3 key sub-questions.
                2. Use the web_search tool to find information for each sub-question.
                3. Use save_note to record important findings as you go.
                4. After gathering enough information, use read_notes to review your notes.
                5. Finally, provide a well-structured summary with key findings, citing sources where possible.
                Be concise but comprehensive.
                """,
        },
    });

// ---------------------------------------------------------------------------
// Interactive loop
// ---------------------------------------------------------------------------
Console.WriteLine("╔══════════════════════════════════════════╗");
Console.WriteLine("║       Research Agent  (type 'exit')      ║");
Console.WriteLine("╚══════════════════════════════════════════╝");
Console.WriteLine();

var history = new List<ChatMessage>();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Topic> ");
    Console.ResetColor();

    string? input = Console.ReadLine();
    if (input is null || input.Equals("exit", StringComparison.OrdinalIgnoreCase))
    {
        break;
    }

    if (string.IsNullOrWhiteSpace(input))
    {
        continue;
    }

    history.Add(new ChatMessage(ChatRole.User, input));

    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine("Researching…");
    Console.ResetColor();

    await foreach (var update in agent.RunStreamingAsync(history))
    {
        foreach (var message in update.Messages)
        {
            if (message.Role == ChatRole.Assistant)
            {
                Console.ForegroundColor = ConsoleColor.Green;
                Console.Write(message.Text);
                Console.ResetColor();
            }
        }
    }

    Console.WriteLine();
    Console.WriteLine();
    notebook.Clear();
}

return 0;

// ---------------------------------------------------------------------------
// Simulated web search  (replace with Bing / Google / SerpAPI for production)
// ---------------------------------------------------------------------------
static async Task<string> WebSearchAsync(string query)
{
    using var http = new HttpClient();
    http.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

    try
    {
        // Use Wikipedia's public search API as a free, keyless search source
        string url = $"https://en.wikipedia.org/w/api.php?action=query&list=search&srsearch={Uri.EscapeDataString(query)}&format=json&utf8=1&srlimit=5";
        using var response = await http.GetAsync(url);
        response.EnsureSuccessStatusCode();

        using var doc = await JsonDocument.CreateAsync(await response.Content.ReadAsStreamAsync());
        var results = doc.RootElement.GetProperty("query").GetProperty("search");

        var sb = new StringBuilder();
        int i = 0;
        foreach (var item in results.EnumerateArray())
        {
            string title = item.GetProperty("title").GetString() ?? "";
            string snippet = item.GetProperty("snippet").GetString() ?? "";
            // Strip HTML tags from snippet
            snippet = System.Text.RegularExpressions.Regex.Replace(snippet, "<.*?>", "");
            sb.AppendLine($"[{++i}] {title}");
            sb.AppendLine($"    https://en.wikipedia.org/wiki/{Uri.EscapeDataString(title.Replace(' ', '_'))}");
            sb.AppendLine($"    {snippet}");
            sb.AppendLine();
        }

        return sb.Length > 0 ? sb.ToString() : "No results found.";
    }
    catch (Exception ex)
    {
        return $"Search failed: {ex.Message}";
    }
}

// ---------------------------------------------------------------------------
// Simple notebook
// ---------------------------------------------------------------------------
sealed class Notebook
{
    private readonly List<(string Title, string Content)> _notes = [];

    public int Count => _notes.Count;

    public void Add(string title, string content) => _notes.Add((title, content));

    public void Clear() => _notes.Clear();

    public override string ToString()
    {
        var sb = new StringBuilder();
        for (int i = 0; i < _notes.Count; i++)
        {
            sb.AppendLine($"--- Note {i + 1}: {_notes[i].Title} ---");
            sb.AppendLine(_notes[i].Content);
            sb.AppendLine();
        }

        return sb.ToString();
    }
}

