// Configuration
// ---------------------------------------------------------------------------
string model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";
string? apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY");
string? endpoint = Environment.GetEnvironmentVariable("OPENAI_ENDPOINT");

if (string.IsNullOrWhiteSpace(apiKey))
{
    Console.Error.WriteLine("Set the OPENAI_API_KEY environment variable.");
    return 1;
}

// ---------------------------------------------------------------------------
// Shared state for the note-taking tool
// ---------------------------------------------------------------------------
var notebook = new Notebook();

// ---------------------------------------------------------------------------
// Tool definitions
// ---------------------------------------------------------------------------
var tools = new List<AITool>
{
    AIFunctionFactory.Create(
        ([Description("The search query to look up on the web")] string query) =>
        {
            return WebSearchAsync(query);
        },
        new AIFunctionFactoryOptions
        {
            Name = "web_search",
            Description = "Search the web for information on a topic. Returns a list of results with titles, URLs, and snippets.",
        }),

    AIFunctionFactory.Create(
        (
            [Description("A short title for this note")] string title,
            [Description("The content / finding to save")] string content
        ) =>
        {
            notebook.Add(title, content);
            return $"Note saved: \"{title}\" (total notes: {notebook.Count})";
        },
        new AIFunctionFactoryOptions
        {
            Name = "save_note",
            Description = "Save a research finding or key point to the notebook for later summarisation.",
        }),

    AIFunctionFactory.Create(
        () =>
        {
            return notebook.Count == 0
                ? "The notebook is empty."
                : notebook.ToString();
        },
        new AIFunctionFactoryOptions
        {
            Name = "read_notes",
            Description = "Read all notes saved so far.",
        }),
};

