    {
        Name = "ResearchAgent",
        Description = "An AI research agent that searches the web and takes notes to produce a summary.",
        ChatOptions = new ChatOptions
        {
            Tools = tools,
            Temperature = 0.2f,
            Instructions = """
                You are a thorough research agent. When given a topic:
                1. Break the topic into 2-3 key sub-questions.
                2. Use the web_search tool to find information for each sub-question.
                3. Use save_note to record important findings as you go.
                4. After gathering enough information, use read_notes to review your notes.
                5. Finally, provide a well-structured summary with key findings, citing sources where possible.
                Be concise but comprehensive.
                """,
        },
    });

// ---------------------------------------------------------------------------
// Interactive loop
// ---------------------------------------------------------------------------
Console.WriteLine("╔══════════════════════════════════════════╗");
Console.WriteLine("║       Research Agent  (type 'exit')      ║");
Console.WriteLine("╚══════════════════════════════════════════╝");
Console.WriteLine();

var history = new List<ChatMessage>();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Topic> ");
    Console.ResetColor();

    string? input = Console.ReadLine();
    if (input is null || input.Equals("exit", StringComparison.OrdinalIgnoreCase))
    {
        break;
    }

    if (string.IsNullOrWhiteSpace(input))
    {
        continue;
    }

    history.Add(new ChatMessage(ChatRole.User, input));

    Console.ForegroundColor = ConsoleColor.DarkGray;
